import {SpotterMainApp} from "../type";
import {GlobalLayoutType, SpotterRouteObject, SpotterRouter} from "../../router";
import { FunctionComponent } from "react";

export interface RouterSystemOptions {
    layout?: {
        [key in GlobalLayoutType]: FunctionComponent
    }
    guard?: {
        element?: FunctionComponent,
        downgradeRoutes?: SpotterRouteObject[]
    }
}

export function boostrapRouterSystem(options: RouterSystemOptions, sptApp: SpotterMainApp) {
    sptApp.router = new SpotterRouter(options)
}
